    municipality: s.municipality,
    county: s.county,
    lat: s.lat,
    lng: s.lng,

    category: 'Riigihaldus',
    dangerPointType: 'PUBLIC_ADMINISTRATION',
    dangerZoneType: 'PUBLIC_DATA_PROXIMITY_CAUTION',
